using System.Collections.Concurrent;
using Microsoft.Extensions.Internal;

namespace Microsoft.AspNetCore.SignalR.StackExchangeRedis.Internal;

internal sealed class AckHandler : IDisposable
{
    private readonly ConcurrentDictionary<int, AckInfo> _acks = new ConcurrentDictionary<int, AckInfo>();
    private readonly Timer _timer;
    private readonly long _ackThreshold = (long)TimeSpan.FromSeconds(30).TotalMilliseconds;
    private readonly TimeSpan _ackInterval = TimeSpan.FromSeconds(5);
    private readonly object _lock = new object();
    private bool _disposed;

    public AckHandler()
    {
        _timer = NonCapturingTimer.Create(state => ((AckHandler)state!).CheckAcks(), state: this, dueTime: _ackInterval, period: _ackInterval);
    }

    public Task CreateAck(int id)
    {
        lock (_lock)
        {
            if (_disposed)
            {
                return Task.CompletedTask;
            }

            return _acks.GetOrAdd(id, _ => new AckInfo()).Tcs.Task;
        }
    }

    public void TriggerAck(int id)
    {
        if (_acks.TryRemove(id, out var ack))
        {
            ack.Tcs.TrySetResult();
        }
    }

    private void CheckAcks()
    {
        if (_disposed)
        {
            return;
        }

        var currentTick = Environment.TickCount64;

        foreach (var pair in _acks)
        {
            var elapsed = currentTick - pair.Value.CreatedTick;
            if (elapsed > _ackThreshold)
            {
                if (_acks.TryRemove(pair.Key, out var ack))
                {
                    ack.Tcs.TrySetCanceled();
                }
            }
        }
    }

    public void Dispose()
    {
        lock (_lock)
        {
            _disposed = true;

            _timer.Dispose();

            foreach (var pair in _acks)
            {
                if (_acks.TryRemove(pair.Key, out var ack))
                {
                    ack.Tcs.TrySetCanceled();
                }
            }
        }
    }

    private sealed class AckInfo
    {
        public TaskCompletionSource Tcs { get; private set; }
        public long CreatedTick { get; private set; }

        public AckInfo()
        {
            CreatedTick = Environment.TickCount64;
            Tcs = new TaskCompletionSource(TaskCreationOptions.RunContinuationsAsynchronously);
        }
    }
}

using OrchardCore.Navigation;

namespace OrchardCore.AdminMenu.Models;

public class AdminNode : MenuItem
{
    public string UniqueId { get; set; } = Guid.NewGuid().ToString("n");

    public bool Enabled { get; set; } = true;

    public AdminNode GetMenuItemById(string id)
    {
        var tempStack = new Stack<AdminNode>(new AdminNode[] { this });

        while (tempStack.Count > 0)
        {
            // Evaluate first node.
            var item = tempStack.Pop();
            if (item.UniqueId.Equals(id, StringComparison.OrdinalIgnoreCase))
            {
                return item;
            }

            // Not that one, continue with the rest.
            foreach (var i in item.Items)
            {
                tempStack.Push((AdminNode)i);
            }
        }

        // Not found.
        return null;
    }

    // Return boolean so that caller can check for success.
    public bool RemoveMenuItem(AdminNode nodeToRemove)
    {
        var tempStack = new Stack<AdminNode>(new AdminNode[] { this });

        while (tempStack.Count > 0)
        {
            // Evaluate first.
            var item = tempStack.Pop();
            if (item.Items.Contains(nodeToRemove))
            {
                item.Items.Remove(nodeToRemove);
                return true; // Success.
            }

            // Not that one, continue.
            foreach (var i in item.Items)
            {
                tempStack.Push((AdminNode)i);
            }
        }

        // Failure.
        return false;
    }

    public bool InsertMenuItem(AdminNode nodeToInsert, MenuItem destinationNode, int position)
    {
        var tempStack = new Stack<AdminNode>(new AdminNode[] { this });
        while (tempStack.Count > 0)
        {
            // Evaluate first.
            var node = tempStack.Pop();
            if (node.Equals(destinationNode))
            {
                node.Items.Insert(position, nodeToInsert);
                return true; // Success.
            }

            // Not that one, continue.
            foreach (var n in node.Items)
            {
                tempStack.Push((AdminNode)n);
            }
        }

        // Failure.
        return false;
    }
}

using Microsoft.AspNetCore.Html;
using OrchardCore.DisplayManagement.Zones;

namespace OrchardCore.DisplayManagement.Title;

public class PageTitleBuilder : IPageTitleBuilder
{
    private static readonly HtmlString _defaultTitleSeparator = new(" - ");

    private readonly List<PositionalTitlePart> _titleParts;
    private HtmlContentBuilder _title;
    private IHtmlContent _fixedTitle;

    public PageTitleBuilder()
    {
        _titleParts = new List<PositionalTitlePart>(5);
    }

    public void SetFixedTitle(IHtmlContent title)
    {
        _fixedTitle = title;
    }

    public void AddSegment(IHtmlContent titlePart, string position)
    {
        _title = null;

        _titleParts.Add(new PositionalTitlePart
        {
            Value = titlePart,
            Position = position,
        });
    }

    public void AddSegments(IEnumerable<IHtmlContent> titleParts, string position)
    {
        foreach (var titlePart in titleParts)
        {
            AddSegment(titlePart, position);
        }
    }

    public IHtmlContent GenerateTitle(IHtmlContent separator)
    {
        if (_fixedTitle != null)
        {
            return _fixedTitle;
        }

        if (_title is { Count: > 0 })
        {
            return _title;
        }

        separator ??= _defaultTitleSeparator;

        _titleParts.Sort(FlatPositionComparer.Instance);

        if (_titleParts.Count == 0)
        {
            return HtmlString.Empty;
        }

        // _titleParts.Count * 2 because we add a separator for each entry
        var htmlContentBuilder = new HtmlContentBuilder(_titleParts.Count * 2);

        for (var i = 0; i < _titleParts.Count; i++)
        {
            htmlContentBuilder.AppendHtml(_titleParts[i].Value);

            if (i < _titleParts.Count - 1)
            {
                htmlContentBuilder.AppendHtml(separator);
            }
        }

        _title = htmlContentBuilder;

        return _title;
    }

    public void Clear()
    {
        _fixedTitle = null;
        _title = null;
        _titleParts.Clear();
    }
}

internal sealed class PositionalTitlePart : IPositioned
{
    public string Position { get; set; }
    public IHtmlContent Value { get; set; }
}

using OrchardCore.DisplayManagement.Shapes;
using OrchardCore.DisplayManagement.Zones;

namespace OrchardCore.DisplayManagement.Views;

public class ShapeViewModel : IShape, IPositioned
{
    public ShapeViewModel()
    {
    }

    public ShapeViewModel(string shapeType)
    {
        ArgumentException.ThrowIfNullOrEmpty(shapeType);

        Metadata.Type = shapeType;
    }

    private ShapeMetadata _metadata;

    public ShapeMetadata Metadata => _metadata ??= new ShapeMetadata();

    public string Position
    {
        get => Metadata.Position;
        set
        {
            Metadata.Position = value;
        }
    }

    public string Id { get; set; }

    public string TagName { get; set; }

    private List<string> _classes;

    public IList<string> Classes => _classes ??= [];

    private Dictionary<string, string> _attributes;

    public IDictionary<string, string> Attributes => _attributes ??= [];

    private Dictionary<string, object> _properties;

    public IDictionary<string, object> Properties => _properties ??= [];

    private bool _sorted;

    private List<IPositioned> _items;

    public IReadOnlyList<IPositioned> Items
    {
        get
        {
            _items ??= [];

            if (!_sorted && _items.Count > 0)
            {
                _items = _items.OrderBy(x => x, FlatPositionComparer.Instance).ToList();
                _sorted = true;
            }

            return _items;
        }
    }

    public ValueTask<IShape> AddAsync(object item, string position)
    {
        if (item == null)
        {
            return ValueTask.FromResult<IShape>(this);
        }

        position ??= string.Empty;
        _sorted = false;
        _items ??= [];

        var wrapped = PositionWrapper.TryWrap(item, position);
        if (wrapped is not null)
        {
            _items.Add(wrapped);
        }

        return ValueTask.FromResult<IShape>(this);
    }
}

using System;
using BlazorAdmin.Services;
using Microsoft.AspNetCore.Components;

namespace BlazorAdmin.Helpers;

public class ToastComponent : ComponentBase, IDisposable
{
    [Inject]
    ToastService ToastService
    {
        get;
        set;
    }
    protected string Heading
    {
        get;
        set;
    }
    protected string Message
    {
        get;
        set;
    }
    protected bool IsVisible
    {
        get;
        set;
    }
    protected string BackgroundCssClass
    {
        get;
        set;
    }
    protected string IconCssClass
    {
        get;
        set;
    }
    protected override void OnInitialized()
    {
        ToastService.OnShow += ShowToast;
        ToastService.OnHide += HideToast;
    }
    private void ShowToast(string message, ToastLevel level)
    {
        BuildToastSettings(level, message);
        IsVisible = true;
        StateHasChanged();
    }
    private void HideToast()
    {
        IsVisible = false;
        StateHasChanged();
    }
    private void BuildToastSettings(ToastLevel level, string message)
    {
        switch (level)
        {
            case ToastLevel.Info:
                BackgroundCssClass = "bg-info";
                IconCssClass = "info";
                Heading = "Info";
                break;
            case ToastLevel.Success:
                BackgroundCssClass = "bg-success";
                IconCssClass = "check";
                Heading = "Success";
                break;
            case ToastLevel.Warning:
                BackgroundCssClass = "bg-warning";
                IconCssClass = "exclamation";
                Heading = "Warning";
                break;
            case ToastLevel.Error:
                BackgroundCssClass = "bg-danger";
                IconCssClass = "times";
                Heading = "Error";
                break;
        }
        Message = message;
    }
    public void Dispose()
    {
        ToastService.OnShow -= ShowToast;
    }
}

